invitation.preprocess:
def process(client, edit, invitation):
    signature = edit.signatures[0] if edit.signatures else None
    if signature not in ['JMLR/Editors_In_Chief', 'JMLR/Production_Editors']:
        raise openreview.OpenReviewException('Mark as Published must be signed as Editors In Chief or Production Editors.')
    if edit.note.content.get('published', {}).get('value') != 'Published':
        raise openreview.OpenReviewException('Select Published to finish the OpenReview publication step.')
    submission = client.get_note(edit.note.forum)
    venueid = submission.content.get('venueid', {}).get('value')
    if venueid != 'JMLR/Camera_Ready_Approved':
        raise openreview.OpenReviewException('Only camera-ready approved papers can be marked as published.')
    if not submission.content.get('publication_metadata', {}).get('value'):
        raise openreview.OpenReviewException('Publication metadata must be generated at camera-ready approval before marking the paper as published.')

